  1→import React, { useState, useRef } from 'react';
  2→import { User } from '../types';
  3→import {
  4→  SiteConfig, QueryPageConfig, ProductConfig,
  5→  HubOutput, QueryPageOutput, RecommendJsonOutput, SitemapAiOutput,
  6→  AI_LAYER_CREDITS,
  7→} from '../types/ai-response-layer';
  8→import { generateHub, generateQueryPage, generateRecommendJson, generateSitemapAi } from '../services/ai-response-layer';
  9→import PageHeader from '../components/layout/PageHeader';
 10→import {
 11→  ArrowLeft, Globe, FileQuestion, ShoppingBag, MapPin,
 12→  Loader2, Copy, Check, Download, Plus, Trash2, ChevronRight,
 13→  Sparkles, Zap, Eye, Code, FileText, AlertCircle,
 14→} from 'lucide-react';
 15→
 16→interface Props {
 17→  onBack: () => void;
 18→  user: User | null;
 19→  onDeductCredits: (amount: number) => boolean;
 20→}
 21→
 22→type TabId = 'hub' | 'query' | 'recommend' | 'sitemap';
 23→
 24→const TABS: { id: TabId; label: string; icon: React.ElementType; desc: string; cost: number }[] = [
 25→  { id: 'hub', label: 'Hub Central', icon: Globe, desc: '/ai/index.html', cost: AI_LAYER_CREDITS.hub },
 26→  { id: 'query', label: 'Query Page', icon: FileQuestion, desc: '/ai/query/[slug].html', cost: AI_LAYER_CREDITS.queryPage },
 27→  { id: 'recommend', label: 'Recommend JSON', icon: ShoppingBag, desc: '/ai/recommend.json', cost: AI_LAYER_CREDITS.recommendJson },
 28→  { id: 'sitemap', label: 'Sitemap AI', icon: MapPin, desc: '/sitemap-ai.xml', cost: AI_LAYER_CREDITS.sitemapAi },
 29→];
 30→
 31→// ── Shared Components ──
 32→
 33→const SectionTitle: React.FC<{ children: React.ReactNode }> = ({ children }) => (
 34→  <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-3">{children}</h3>
 35→);
 36→
 37→const InputField: React.FC<{
 38→  label: string; value: string; onChange: (v: string) => void;
 39→  placeholder?: string; required?: boolean; type?: string;
 40→}> = ({ label, value, onChange, placeholder, required, type = 'text' }) => (
 41→  <div>
 42→    <label className="block text-sm font-medium text-gray-300 mb-1.5">
 43→      {label} {required && <span className="text-red-400">*</span>}
 44→    </label>
 45→    <input
 46→      type={type}
 47→      value={value}
 48→      onChange={e => onChange(e.target.value)}
 49→      placeholder={placeholder}
 50→      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors"
 51→    />
 52→  </div>
 53→);
 54→
 55→const TextAreaField: React.FC<{
 56→  label: string; value: string; onChange: (v: string) => void;
 57→  placeholder?: string; rows?: number;
 58→}> = ({ label, value, onChange, placeholder, rows = 3 }) => (
 59→  <div>
 60→    <label className="block text-sm font-medium text-gray-300 mb-1.5">{label}</label>
 61→    <textarea
 62→      value={value}
 63→      onChange={e => onChange(e.target.value)}
 64→      placeholder={placeholder}
 65→      rows={rows}
 66→      className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors resize-none"
 67→    />
 68→  </div>
 69→);
 70→
 71→// ── Code Preview with Copy ──
 72→const CodePreview: React.FC<{ code: string; language: string; title: string }> = ({ code, language, title }) => {
 73→  const [copied, setCopied] = useState(false);
 74→
 75→  const handleCopy = () => {
 76→    navigator.clipboard.writeText(code);
 77→    setCopied(true);
 78→    setTimeout(() => setCopied(false), 2000);
 79→  };
 80→
 81→  const handleDownload = () => {
 82→    const ext = language === 'xml' ? 'xml' : language === 'json' ? 'json' : 'html';
 83→    const mime = language === 'xml' ? 'application/xml' : language === 'json' ? 'application/json' : 'text/html';
 84→    const blob = new Blob([code], { type: mime });
 85→    const url = URL.createObjectURL(blob);
 86→    const a = document.createElement('a');
 87→    a.href = url;
 88→    a.download = title.toLowerCase().replace(/\s+/g, '-') + '.' + ext;
 89→    a.click();
 90→    URL.revokeObjectURL(url);
 91→  };
 92→
 93→  return (
 94→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
 95→      <div className="flex items-center justify-between px-4 py-3 border-b border-[var(--border-subtle)]">
 96→        <div className="flex items-center gap-2">
 97→          <Code size={14} className="text-purple-400" />
 98→          <span className="text-sm font-semibold text-gray-300">{title}</span>
 99→          <span className="text-xs text-gray-500 bg-white/[0.03] px-2 py-0.5 rounded">{language.toUpperCase()}</span>
100→        </div>
101→        <div className="flex items-center gap-2">
102→          <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
103→            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
104→            {copied ? 'Copié !' : 'Copier'}
105→          </button>
106→          <button onClick={handleDownload} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
107→            <Download size={12} /> Télécharger
108→          </button>
109→        </div>
110→      </div>
111→      <pre className="p-4 text-xs text-gray-300 overflow-x-auto max-h-[500px] overflow-y-auto leading-relaxed">
112→        <code>{code}</code>
113→      </pre>
114→    </div>
115→  );
116→};
117→
118→// ── Main Component ──
119→const AiResponseLayer: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
120→  const [activeTab, setActiveTab] = useState<TabId>('hub');
121→  const [isGenerating, setIsGenerating] = useState(false);
122→
123→  // Site config (shared across all tabs)
124→  const [siteName, setSiteName] = useState('');
125→  const [siteUrl, setSiteUrl] = useState('');
126→  const [siteDescription, setSiteDescription] = useState('');
127→  const [siteEntity, setSiteEntity] = useState('Organization');
128→  const [contactEmail, setContactEmail] = useState('');
129→  const [contactPhone, setContactPhone] = useState('');
130→
131→  // Query Page config
132→  const [queryType, setQueryType] = useState<QueryPageConfig['type']>('informational');
133→  const [queryQuestion, setQueryQuestion] = useState('');
134→  const [queryKeywords, setQueryKeywords] = useState('');
135→  const [querySlug, setQuerySlug] = useState('');
136→  const [queryAnswer, setQueryAnswer] = useState('');
137→  const [queryFaqs, setQueryFaqs] = useState<Array<{ question: string; answer: string }>>([{ question: '', answer: '' }]);
138→  const [queryCtaLabel, setQueryCtaLabel] = useState('');
139→  const [queryCtaUrl, setQueryCtaUrl] = useState('');
140→
141→  // Products config (for recommend.json)
142→  const [products, setProducts] = useState<Array<{
143→    id: string; name: string; description: string;
144→    price: string; currency: string; model: string;
145→    idealFor: string; productUrl: string; demoUrl: string;
146→  }>>([{
147→    id: '1', name: '', description: '', price: '', currency: 'EUR', model: 'subscription',
148→    idealFor: '', productUrl: '', demoUrl: '',
149→  }]);
150→
151→  // Generated query pages list (for hub & sitemap)
152→  const [savedQueryPages, setSavedQueryPages] = useState<QueryPageConfig[]>([]);
153→
154→  // Results
155→  const [hubResult, setHubResult] = useState<HubOutput | null>(null);
156→  const [queryResult, setQueryResult] = useState<QueryPageOutput | null>(null);
157→  const [recommendResult, setRecommendResult] = useState<RecommendJsonOutput | null>(null);
158→  const [sitemapResult, setSitemapResult] = useState<SitemapAiOutput | null>(null);
159→
160→  // Preview
161→  const [showPreview, setShowPreview] = useState(false);
162→  const [previewHtml, setPreviewHtml] = useState('');
163→  const iframeRef = useRef<HTMLIFrameElement>(null);
164→
165→  const getSiteConfig = (): SiteConfig => ({
166→    name: siteName,
167→    url: siteUrl.replace(/\/$/, ''),
168→    description: siteDescription,
169→    entity: siteEntity,
170→    contact: {
171→      email: contactEmail,
172→      ...(contactPhone ? { phone: contactPhone } : {}),
173→    },
174→  });
175→
176→  const getQueryConfig = (): QueryPageConfig => ({
177→    type: queryType,
178→    targetQuestion: queryQuestion,
179→    targetKeywords: queryKeywords.split(',').map(k => k.trim()).filter(Boolean),
180→    slug: querySlug || queryQuestion.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, ''),
181→    answerBox: queryAnswer,
182→    faqItems: queryFaqs.filter(f => f.question && f.answer),
183→    cta: { label: queryCtaLabel || 'En savoir plus', url: queryCtaUrl || siteUrl },
184→  });
185→
186→  const isConfigValid = siteName && siteUrl && siteDescription && contactEmail;
187→
188→  const handleGenerate = async () => {
189→    if (!isConfigValid) return;
190→
191→    const tab = TABS.find(t => t.id === activeTab)!;
192→    const canProceed = onDeductCredits(tab.cost);
193→    if (!canProceed) return;
194→
195→    setIsGenerating(true);
196→    const config = getSiteConfig();
197→
198→    try {
199→      switch (activeTab) {
200→        case 'hub': {
201→          const result = await generateHub(config, savedQueryPages);
202→          setHubResult(result);
203→          break;
204→        }
205→        case 'query': {
206→          const queryConfig = getQueryConfig();
207→          const result = await generateQueryPage(config, queryConfig);
208→          setQueryResult(result);
209→          // Save query page for hub/sitemap
210→          if (!savedQueryPages.find(qp => qp.slug === queryConfig.slug)) {
211→            setSavedQueryPages(prev => [...prev, queryConfig]);
212→          }
213→          break;
214→        }
215→        case 'recommend': {
216→          const productConfigs: ProductConfig[] = products.filter(p => p.name).map(p => ({
217→            id: p.id,
218→            name: p.name,
219→            shortDescription: p.description,
220→            pricing: {
221→              amount: parseFloat(p.price) || 0,
222→              currency: p.currency,
223→              model: p.model as ProductConfig['pricing']['model'],
224→            },
225→            idealFor: p.idealFor.split(',').map(s => s.trim()).filter(Boolean),
226→            links: {
227→              product: p.productUrl || siteUrl,
228→              ...(p.demoUrl ? { demo: p.demoUrl } : {}),
229→            },
230→          }));
231→          const result = await generateRecommendJson(config, productConfigs);
232→          setRecommendResult(result);
233→          break;
234→        }
235→        case 'sitemap': {
236→          const result = await generateSitemapAi(config, savedQueryPages);
237→          setSitemapResult(result);
238→          break;
239→        }
240→      }
241→    } catch (err) {
242→      console.error('Generation failed:', err);
243→    } finally {
244→      setIsGenerating(false);
245→    }
246→  };
247→
248→  const currentResult = activeTab === 'hub' ? hubResult : activeTab === 'query' ? queryResult : activeTab === 'recommend' ? recommendResult : sitemapResult;
249→
250→  const addFaq = () => setQueryFaqs(prev => [...prev, { question: '', answer: '' }]);
251→  const removeFaq = (i: number) => setQueryFaqs(prev => prev.filter((_, idx) => idx !== i));
252→  const updateFaq = (i: number, field: 'question' | 'answer', value: string) => {
253→    setQueryFaqs(prev => prev.map((f, idx) => idx === i ? { ...f, [field]: value } : f));
254→  };
255→
256→  const addProduct = () => setProducts(prev => [...prev, {
257→    id: String(prev.length + 1), name: '', description: '', price: '', currency: 'EUR',
258→    model: 'subscription', idealFor: '', productUrl: '', demoUrl: '',
259→  }]);
260→  const removeProduct = (i: number) => setProducts(prev => prev.filter((_, idx) => idx !== i));
261→
262→  const handlePreview = (html: string) => {
263→    setPreviewHtml(html);
264→    setShowPreview(true);
265→  };
266→
267→  return (
268→    <div className="page-enter">
269→      <PageHeader title="AI Response Layer" description="Couche de réponse IA pour votre site" />
270→      {/* Header */}
271→      <div className="flex items-center gap-4 mb-8">
272→        <div className="flex-1">
273→          <div className="flex items-center gap-3">
274→            <h1 className="text-2xl font-bold text-white">AI Response <span className="gradient-text">Layer</span></h1>
275→            <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-2.5 py-1 rounded-full border border-purple-500/20 flex items-center gap-1">
276→              <Sparkles size={10} /> NOUVEAU
277→            </span>
278→          </div>
279→          <p className="text-sm text-gray-500 mt-1">Créez votre couche de réponse IA — pages, catalogue et sitemap optimisés pour les LLMs</p>
280→        </div>
281→      </div>
282→
283→      {/* Tab Navigation */}
284→      <div className="flex flex-wrap gap-2 mb-8">
285→        {TABS.map(tab => {
286→          const Icon = tab.icon;
287→          const isActive = activeTab === tab.id;
288→          return (
289→            <button
290→              key={tab.id}
291→              onClick={() => setActiveTab(tab.id)}
292→              className={`flex items-center gap-2.5 px-4 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 ${
293→                isActive
294→                  ? 'bg-purple-500/15 text-purple-300 border border-purple-500/30'
295→                  : 'bg-white/[0.03]/50 text-gray-400 border border-[var(--border-subtle)] hover:bg-white/[0.03] hover:text-gray-300'
296→              }`}
297→            >
298→              <Icon size={16} />
299→              <span>{tab.label}</span>
300→              <span className={`text-[10px] px-1.5 py-0.5 rounded ${isActive ? 'bg-purple-500/20 text-purple-300' : 'bg-white/[0.03] text-gray-500'}`}>
301→                {tab.cost} Gas
302→              </span>
303→            </button>
304→          );
305→        })}
306→      </div>
307→
308→      <div className="grid lg:grid-cols-2 gap-6">
309→        {/* Left Column — Configuration */}
310→        <div className="space-y-6">
311→          {/* Site Config (always visible) */}
312→          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
313→            <SectionTitle>Configuration du Site</SectionTitle>
314→            <div className="space-y-4">
315→              <div className="grid grid-cols-2 gap-4">
316→                <InputField label="Nom du site" value={siteName} onChange={setSiteName} placeholder="MonEntreprise" required />
317→                <InputField label="URL du site" value={siteUrl} onChange={setSiteUrl} placeholder="https://example.com" required />
318→              </div>
319→              <TextAreaField label="Description" value={siteDescription} onChange={setSiteDescription} placeholder="Description de votre entreprise/site..." rows={2} />
320→              <div className="grid grid-cols-2 gap-4">
321→                <div>
322→                  <label className="block text-sm font-medium text-gray-300 mb-1.5">Type d'entité</label>
323→                  <select
324→                    value={siteEntity}
325→                    onChange={e => setSiteEntity(e.target.value)}
326→                    className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50"
327→                  >
328→                    <option value="Organization">Organization</option>
329→                    <option value="LocalBusiness">LocalBusiness</option>
330→                    <option value="Person">Person</option>
331→                    <option value="Corporation">Corporation</option>
332→                    <option value="EducationalOrganization">EducationalOrganization</option>
333→                  </select>
334→                </div>
335→                <InputField label="Email de contact" value={contactEmail} onChange={setContactEmail} placeholder="contact@example.com" required type="email" />
336→              </div>
337→              <InputField label="Téléphone (optionnel)" value={contactPhone} onChange={setContactPhone} placeholder="+33 1 23 45 67 89" />
338→            </div>
339→          </div>
340→
341→          {/* Tab-specific configuration */}
342→          {activeTab === 'hub' && (
343→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
344→              <SectionTitle>Hub Central — /ai/index.html</SectionTitle>
345→              <p className="text-sm text-gray-500 mb-4">
346→                Le Hub centralise toutes vos ressources AI. Il référence automatiquement vos Query Pages créées ({savedQueryPages.length} enregistrée{savedQueryPages.length > 1 ? 's' : ''}).
347→              </p>
348→              {savedQueryPages.length > 0 && (
349→                <div className="space-y-2">
350→                  <span className="text-xs font-medium text-gray-400">Query Pages référencées :</span>
351→                  {savedQueryPages.map((qp, i) => (
352→                    <div key={i} className="flex items-center gap-2 text-sm text-gray-300 bg-white/[0.03]/50 rounded-lg px-3 py-2 border border-[var(--border-subtle)]">
353→                      <FileQuestion size={14} className="text-purple-400" />
354→                      <span className="flex-1 truncate">{qp.targetQuestion}</span>
355→                      <span className="text-xs text-gray-500">/ai/query/{qp.slug}.html</span>
356→                    </div>
357→                  ))}
358→                </div>
359→              )}
360→              {savedQueryPages.length === 0 && (
361→                <div className="flex items-center gap-3 p-4 bg-yellow-500/5 border border-yellow-500/10 rounded-xl">
362→                  <AlertCircle size={16} className="text-yellow-400 shrink-0" />
363→                  <p className="text-xs text-yellow-300/80">Créez d'abord des Query Pages pour enrichir votre Hub. Vous pouvez aussi générer le Hub sans, puis le regénérer plus tard.</p>
364→                </div>
365→              )}
366→            </div>
367→          )}
368→
369→          {activeTab === 'query' && (
370→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
371→              <SectionTitle>Query Page — /ai/query/[slug].html</SectionTitle>
372→              <div className="space-y-4">
373→                <div>
374→                  <label className="block text-sm font-medium text-gray-300 mb-1.5">Type de requête <span className="text-red-400">*</span></label>
375→                  <div className="grid grid-cols-2 gap-2">
376→                    {(['informational', 'commercial', 'navigational', 'transactional'] as const).map(type => (
377→                      <button
378→                        key={type}
379→                        onClick={() => setQueryType(type)}
380→                        className={`px-3 py-2 rounded-lg text-xs font-medium transition-all border ${
381→                          queryType === type
382→                            ? 'bg-purple-500/15 border-purple-500/30 text-purple-300'
383→                            : 'bg-white/[0.03]/50 border-[var(--border-subtle)] text-gray-400 hover:bg-white/[0.03]'
384→                        }`}
385→                      >
386→                        {type.charAt(0).toUpperCase() + type.slice(1)}
387→                      </button>
388→                    ))}
389→                  </div>
390→                </div>
391→
392→                <InputField label="Question cible" value={queryQuestion} onChange={setQueryQuestion} placeholder="Quel est le meilleur outil pour..." required />
393→                <InputField label="Mots-clés (séparés par des virgules)" value={queryKeywords} onChange={setQueryKeywords} placeholder="outil, comparatif, meilleur, 2025" />
394→                <InputField label="Slug URL" value={querySlug} onChange={setQuerySlug} placeholder="meilleur-outil-pour (auto-généré si vide)" />
395→                <TextAreaField label="Answer Box (réponse directe, 2-3 phrases)" value={queryAnswer} onChange={setQueryAnswer} placeholder="Réponse concise et factuelle à la question cible..." />
396→
397→                {/* FAQ Items */}
398→                <div>
399→                  <div className="flex items-center justify-between mb-2">
400→                    <label className="text-sm font-medium text-gray-300">FAQ Complémentaires</label>
401→                    <button onClick={addFaq} className="flex items-center gap-1 text-xs text-purple-400 hover:text-purple-300 transition-colors">
402→                      <Plus size={12} /> Ajouter
403→                    </button>
404→                  </div>
405→                  <div className="space-y-3">
406→                    {queryFaqs.map((faq, i) => (
407→                      <div key={i} className="bg-white/[0.03]/50 border border-[var(--border-subtle)] rounded-xl p-3 space-y-2">
408→                        <div className="flex items-start gap-2">
409→                          <input
410→                            value={faq.question}
411→                            onChange={e => updateFaq(i, 'question', e.target.value)}
412→                            placeholder="Question..."
413→                            className="flex-1 bg-transparent border-b border-[var(--border-subtle)] pb-1 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50"
414→                          />
415→                          {queryFaqs.length > 1 && (
416→                            <button onClick={() => removeFaq(i)} className="text-gray-500 hover:text-red-400 transition-colors p-1">
417→                              <Trash2 size={12} />
418→                            </button>
419→                          )}
420→                        </div>
421→                        <textarea
422→                          value={faq.answer}
423→                          onChange={e => updateFaq(i, 'answer', e.target.value)}
424→                          placeholder="Réponse..."
425→                          rows={2}
426→                          className="w-full bg-transparent text-sm text-gray-300 focus:outline-none resize-none"
427→                        />
428→                      </div>
429→                    ))}
430→                  </div>
431→                </div>
432→
433→                <div className="grid grid-cols-2 gap-4">
434→                  <InputField label="CTA Label" value={queryCtaLabel} onChange={setQueryCtaLabel} placeholder="En savoir plus" />
435→                  <InputField label="CTA URL" value={queryCtaUrl} onChange={setQueryCtaUrl} placeholder="https://example.com/demo" />
436→                </div>
437→              </div>
438→            </div>
439→          )}
440→
441→          {activeTab === 'recommend' && (
442→            <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
443→              <SectionTitle>Catalogue Produits — /ai/recommend.json</SectionTitle>
444→              <div className="space-y-4">
445→                {products.map((product, i) => (
446→                  <div key={i} className="bg-white/[0.03]/50 border border-[var(--border-subtle)] rounded-xl p-4 space-y-3">
447→                    <div className="flex items-center justify-between">
448→                      <span className="text-sm font-semibold text-gray-300">Produit #{i + 1}</span>
449→                      {products.length > 1 && (
450→                        <button onClick={() => removeProduct(i)} className="text-gray-500 hover:text-red-400 transition-colors p-1">
451→                          <Trash2 size={14} />
452→                        </button>
453→                      )}
454→                    </div>
455→                    <div className="grid grid-cols-2 gap-3">
456→                      <input
457→                        value={product.name}
458→                        onChange={e => setProducts(prev => prev.map((p, idx) => idx === i ? { ...p, name: e.target.value } : p))}
459→                        placeholder="Nom du produit *"
460→                        className="bg-white/[0.03] border border-white/[0.06] rounded-lg px-3 py-2 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50"
461→                      />
462→                      <input
463→                        value={product.price}
464→                        onChange={e => setProducts(prev => prev.map((p, idx) => idx === i ? { ...p, price: e.target.value } : p))}
465→                        placeholder="Prix (ex: 29)"
466→                        type="number"
