327→function StatCard({ label, value, subtext, color }: { label: string; value: string; subtext?: string; color: string }) {
328→  return (
329→    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
330→      <div className="text-[11px] uppercase tracking-wider text-zinc-600 font-medium">{label}</div>
331→      <div className={`text-2xl font-bold mt-1 ${color}`}>{value}</div>
332→      {subtext && <div className="text-[13px] text-zinc-500 mt-0.5">{subtext}</div>}
333→    </div>
334→  );
335→}
336→
337→interface QueryGroup {
338→  queryId: string;
339→  query: string;
340→  engines: { engine: string; cited: boolean; position: string; sentiment: string }[];
341→  competitors: string[];
342→}
343→
344→function groupByQuery(results: LanguageCitationResult[]): QueryGroup[] {
345→  const groups: Record<string, QueryGroup> = {};
346→
347→  for (const r of results) {
348→    if (!groups[r.queryId]) {
349→      groups[r.queryId] = {
350→        queryId: r.queryId,
351→        query: r.query,
352→        engines: [],
353→        competitors: [],
354→      };
355→    }
356→    groups[r.queryId].engines.push({
357→      engine: r.engine,
358→      cited: r.cited,
359→      position: r.position,
360→      sentiment: r.sentiment,
361→    });
362→    for (const comp of r.competitorsCited) {
363→      if (!groups[r.queryId].competitors.includes(comp)) {
364→        groups[r.queryId].competitors.push(comp);
365→      }
366→    }
367→  }
368→
369→  return Object.values(groups);
370→}
