type TabId = 'hub' | 'query' | 'recommend' | 'sitemap';

const TABS: { id: TabId; label: string; icon: React.ElementType; desc: string; cost: number }[] = [
  { id: 'hub', label: 'Hub Central', icon: Globe, desc: '/ai/index.html', cost: AI_LAYER_CREDITS.hub },
  { id: 'query', label: 'Query Page', icon: FileQuestion, desc: '/ai/query/[slug].html', cost: AI_LAYER_CREDITS.queryPage },
  { id: 'recommend', label: 'Recommend JSON', icon: ShoppingBag, desc: '/ai/recommend.json', cost: AI_LAYER_CREDITS.recommendJson },
  { id: 'sitemap', label: 'Sitemap AI', icon: MapPin, desc: '/sitemap-ai.xml', cost: AI_LAYER_CREDITS.sitemapAi },
];

// ── Code Preview with Copy ──
const CodePreview: React.FC<{ code: string; language: string; title: string }> = ({ code, language, title }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = () => {
    const ext = language === 'xml' ? 'xml' : language === 'json' ? 'json' : 'html';
    const mime = language === 'xml' ? 'application/xml' : language === 'json' ? 'application/json' : 'text/html';
    const blob = new Blob([code], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = title.toLowerCase().replace(/\s+/g, '-') + '.' + ext;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl overflow-hidden">
      <div className="flex items-center justify-between px-4 py-3 border-b border-[var(--border-subtle)]">
        <div className="flex items-center gap-2">
          <Code size={14} className="text-purple-400" />
          <span className="text-sm font-semibold text-gray-300">{title}</span>
          <span className="text-xs text-gray-500 bg-white/[0.03] px-2 py-0.5 rounded">{language.toUpperCase()}</span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleCopy} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
            {copied ? <Check size={12} className="text-emerald-400" /> : <Copy size={12} />}
            {copied ? 'Copié !' : 'Copier'}
          </button>
          <button onClick={handleDownload} className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-purple-400 transition-colors px-2 py-1 rounded hover:bg-white/[0.03]">
            <Download size={12} /> Télécharger
          </button>
        </div>
      </div>
      <pre className="p-4 text-xs text-gray-300 overflow-x-auto max-h-[500px] overflow-y-auto leading-relaxed">
        <code>{code}</code>
      </pre>
    </div>
  );
};

